const out = [];
const body = ($input.first().json.body) || {};
for (const e of (body.entry||[])) {
  for (const ch of (e.changes||[])) {
    const v = ch.value || {};
    const nameByWa = {};
    for (const c of (v.contacts||[])) nameByWa[c.wa_id] = (c.profile && c.profile.name) || null;
    for (const m of (v.messages||[])) {
      let text='';
      if (m.type==='text') text=(m.text&&m.text.body)||'';
      else if (m.type==='button') text=(m.button&&m.button.text)||'';
      else if (m.type==='interactive') { const it=m.interactive||{}; text=(it.list_reply&&it.list_reply.title)||(it.button_reply&&it.button_reply.title)||''; }
      else text='['+m.type+']';
      out.push({json:{kind:'message',phone:m.from,name:nameByWa[m.from]||null,wamid:m.id,ts:Number(m.timestamp)||Math.floor(Date.now()/1000),type:(m.type==='text'?'text':m.type),text}});
    }
    for (const s of (v.statuses||[])) out.push({json:{kind:'status',wamid:s.id,status:s.status}});
  }
}
return out;
